INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09894b5","title":"Человек-Паук. Новый день. Том 4","author":"Дэн Слотт,Марк Уэйд,Марк Гуггенхайм,Фред Ван Ленте,Роджер Стерн,Джозеф Келли,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004713123/140/4715/__ChelovekPauk._Novyj_den._Tom_4.jpg","isbn":"978-5-04-111673-6","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"Книги на букву \"Щ\"","genres":["Комиксы","манга","графические романы"],"annotation":"Роман тёти Мэй и Джей Джоны Джеймона – старшего стремительно развивается и движется к свадьбе. Норман Озборн, в конец обезумевший от власти в эпоху Тёмного правления, решает использовать собственного сына Гарри для обретения ещё большей народной любви. и даже Отто Октавиус, претерпев десятки жестоких избиений за свою злодейскую карьеру, решает вернуться и подарить человечеству прощальный «подарок».  Но всё это — сущие пустяки в сравнении с настоящей угрозой: Джей Джона Джеймсон – младший, тот самый бывший издатель «Дэйли Бьюгл» стал мэром! И теперь, будьте уверены, старый хрыч с усами Гитлера использует все новообретённые возможности, чтобы посадить Паучка за решётку! Но наш герой тоже не лыком шит — собрав всю свою сверхчеловеческую выносливость, Питер выходит на новый уровень и начинает геройствовать 24/7. Чего только не сделаешь ради победы над самым злейшим своим врагом!  Но лучше бы Человеку-Пауку не перетрудиться в его попытках насолить мэру... ведь в городе объявился новый Стервятник, краснопёрый и плюющийся кислотой! Уж с таким-то устрашающим монстром не совладать, когда тебя одолевает недосып...  В сборник вошли выпуски серий \"Удивительный Человек-паук. Том 1\" #592-601, Ежегодник #36, \"Тёмное правление. Мистер Негатив\" #1-3[/work, история из антологии \"Удивительная семья Человека-Паука\" #7 и одиночный выпуск.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":4,"review":"","added":9999541,"hdCover":""},{"id":"09894b4","title":"Daredevil/Punisher: Seventh Circle","author":"Чарльз Соул","type":"Книга","cover":"https://i.livelib.ru/workpic/1005631195/140/74c1/Charlz_Soul__DaredevilPunisher_Seventh_Circle.jpg","isbn":"","publisher":"","pubDate":"","language":"Английский","series":"","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":4.5,"review":"","added":9999540,"hdCover":""},{"id":"09894b3","title":"Сорвиголова. Том 4. Автобиография Мэтта Мёрдока","author":"Марк Уэйд","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002919688/140/f80a/Mark_Uejd__Sorvigolova._Tom_4._Avtobiografiya_Metta_Mjordoka.jpg","isbn":"978-5-91339-718-8","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Всё сводится к этому: чтобы сохранить новую жизнь, которую ему удалось построить, и друзей, что его окружают, Сорвиголове предстоит решиться на нечто чрезвычайно важное, и это нечто может означать смерть Мэтта Мёрдока! Человек без Страха должен заключить сделку со своим личным дьяволом, и пока нашему герою не удастся перехитрить самого сильного и могучего противника в его жизни, никто не уйдёт живым! Неужели время Сорвиголовы в Сан-Франциско подходит к концу? Неужто появившийся в городе новый враг споёт поминальную песню Мёрдоку и его друзьям? Одно известно наверняка: не всем удастся пережить этот период в жизни Сорвиголовы, а финальная глава «Автобиографии Мэтта Мёрдока» будет написана кем-то, кто вас удивит. Узнайте, кто останется жив, кто погибнет, а кто — навеки изменится.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":3,"review":"","added":9999539,"hdCover":""},{"id":"09894b2","title":"Сорвиголова. Том 3. Тот самый Сорвиголова","author":"Крис Сэмни,Марк Уэйд","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002824721/140/6386/__Sorvigolova._Tom_3._Tot_samyj_Sorvigolova.jpg","isbn":"978-5-91339-675-4","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"Сорвиголова","genres":["Комиксы","манга","графические романы"],"annotation":"Вселенная Marvel пошатнётся, ведь Марк Уэйд и Крис Сэмни медленно подбираются к потрясающей кульминации любимой многими серии-лауреата премии Айснера и возвращают одного из старейших (а теперь ещё) и опаснейших врагов Мэтта Мёрдока. Но кого именно? Цепочка таинственных событий тянется всё дальше, и внезапно Сорвиголове приходится разбираться с психологическими травмами последних лет! Мэтт Мёрдок пишет автобиографию, сталкивается с самыми тёмными демонами своей души и сильно меняется. Кирстен и Фогги не нравится человек, в которого превращается Сорвиголова, и полицейские Сан-Франциско с ними солидарны. Пока Филин приводит в действие свой зловещий план, ещё один старый противник Мэтта готовится ударить исподтишка. Мэтту предстоит сделать трудный выбор, но не станет ли этот выбор опрометчивым? Специальный гость сборника: Супертрюкач!  Сборник включает выпуски \"Сорвиголова\" (2014) #11-15, написанные Марком Уэйдом и проиллюстрированные Крисом Сэмни.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":3.5,"review":"","added":9999538,"hdCover":""},{"id":"09894b1","title":"Сорвиголова. Том 2. На Западном Побережье не без перемен","author":"Марк Уэйд","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002784058/140/0114/Mark_Uejd__Sorvigolova._Tom_2._Na_Zapadnom_Poberezhe_ne_bez_peremen.jpg","isbn":"978-5-91339-635-8","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Мэтт Мердок перебрался в Сан-Франциско в поисках новой работы, но вдобавок получил и новые проблемы! Враги из прошлого продолжают преследовать Человека без страха, да и новых хоть отбавляй. Загадочные исчезновения монахинь, вторжение в посольство Ваканды, пропавшие дети и многие другие неприятности ждут Сорвиголову в этом томе!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":2.5,"review":"","added":9999537,"hdCover":""},{"id":"09894b0","title":"Сорвиголова. Том 1. Дьявол Залива","author":"Марк Уэйд","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002607860/140/501a/Mark_Uejd__Sorvigolova._Tom_1._Dyavol_Zaliva.jpg","isbn":"978-5-91339-549-8","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Сорвиголова отправляется на запад, чтобы защищать от зла улицы Золотого города в обеих своих ипостасях: героя в маске и незрячего адвоката Мэтта Мёрдока! Его ждут отличные возможности: прошлое следует по пятам, а старые знакомые появляются вновь, чтобы отомстить. Возвращается Филин. он изменился до неузнаваемости, смертельно опасен и работает не один! Но старые враги - просто мелкие сошки по сравнению с новым \"другом\" Мэтта: недогероем по прозвищу Саван! Кроме того, у Кирстен и Мэтта есть общий секрет, который всё сложнее держать в тайне. И из-за чего умер Фогги Нельсон?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":3,"review":"","added":9999536,"hdCover":""},{"id":"09894af","title":"Daredevil: Blood of the Tarantula","author":"Эд Брубейкер,Энди Паркс","type":"Книга","cover":"https://i.livelib.ru/workpic/1005630121/140/7c76/__Daredevil_Blood_of_the_Tarantula.jpg","isbn":"","publisher":"Marvel","pubDate":"","language":"Английский","series":"","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":3.5,"review":"","added":9999535,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09894ae","title":"Daredevil: Road Warrior","author":"Марк Уэйд,Питер Краус,Джош Калиш","type":"Книга","cover":"https://i.livelib.ru/workpic/1005630031/140/719c/__Daredevil_Road_Warrior.jpg","isbn":"","publisher":"","pubDate":"","language":"","series":"","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":4,"review":"","added":9999534,"hdCover":""},{"id":"09894ad","title":"Чудо-Женщина. Гикетейя","author":"Грег Рака,Дж. Дж. Джонс,Дэйв Стюарт,Уэйд фон Гробаджер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005139462/140/27d9/__ChudoZhenschina._Giketejya.jpg","isbn":"978-5-389-17696-6","publisher":"Азбука, Азбука-Аттикус","pubDate":"2020","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Гикетейя – древнегреческий обряд, связывающий господина и слугу отношениями взаимного уважения и служения. Принцесса Диана Фемискирская, которую большой мир знает как великолепную Чудо-Женщину, вынуждена укрывать у себя Даниэллу Уэллис – хорошую девушку с плохим прошлым. Чудо-Женщина обязана защищать и наставлять свою просительницу, поскольку гикетейя – это договоренность, которую нельзя нарушить, не рискуя навлечь на себя гнев богов.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":3,"review":"","added":9999533,"hdCover":""},{"id":"09894ac","title":"Wonder Woman Vol. 9: Resurrection","author":"David Finch,Мередит Финч","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001980437/140/7297/__Wonder_Woman_Vol._9_Resurrection.jpg","isbn":"978-1401265847","publisher":"DC Comics","pubDate":"2016","language":"Английский","series":"","genres":[],"annotation":"She’s the God of War, but Diana of Themyscira—a.k.a. Wonder Woman—is about to discover an enemy deadlier than any she’s ever encountered. An illness has been unleashed that could destroy every Olympian left alive, and it’s starting with the most vulnerable demigod of them all: baby Zeke, the son of Zeus—and the person Diana cares about above all else.  To save the child and protect her immortal kin, Wonder Woman must begin a perilous quest. Old allies and enemies alike will return—but will they help or hinder her? Her home on Paradise Island awaits—but will her homecoming plunge her into hell itself? And shocking revelations are coming—will they cause the Amazon warrior to question everything she thought she knew about her family, her friends…and even herself? Find out in WONDER WOMAN VOL. 9: RESURRECTION, from the creative team of Meredith Finch (TALES FROM OZ) and David Finch (BATMAN: THE DARK KNIGHT), with help from other talented artists including Miguel Mendonça (TEEN TITANS), Scott Hanna (GREEN LANTERN CORPS) and more! Collecting issues #48-52 of the acclaimed series, this stunning chapter in the Wonder Woman saga features surprises that will raise the dead! This volume also includes a special preview of WONDER WOMAN: REBIRTH #1!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":2.5,"review":"","added":9999532,"hdCover":""},{"id":"09894ab","title":"Wonder Woman Vol. 8: A Twist of Faith","author":"David Finch,Мередит Финч","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001980433/140/c1d8/__Wonder_Woman_Vol._8_A_Twist_of_Faith.jpg","isbn":"978-1401261641","publisher":"DC Comics","pubDate":"2016","language":"Английский","series":"","genres":[],"annotation":"A daring new direction begins with the arrival of a brand new villain in these stories from WONDER WOMAN #41-47! But while he may be new to us, he''s not new to the world he seeks to tame. And speaking of villains, Donna Troy''s quest to destroy Wonder Woman ratchets up another gear (if that''s even possible!), while Wonder Woman is learning how to replace Ares as God of War. Plus, Donna Troy''s fate becomes clear as she embarks on a journey that will either end her life or begin a new one, while Wonder Woman draws closer to the Amazon who tried to depose Diana as queen!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":2,"review":"","added":9999531,"hdCover":""},{"id":"09894aa","title":"Wonder Woman Vol. 7: War-Torn","author":"David Finch,Мередит Финч","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001847081/140/77af/__Wonder_Woman_Vol._7_WarTorn.jpg","isbn":"9781401256791","publisher":"DC Comics","pubDate":"2015","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"The new God of War, Diana of Themyscira finds that conflict follows her wherever she goes. As Wonder Woman, she must help the Justice League to stop a mysterious evil that’s claiming countless innocent victims. As Queen of the Amazons, she’s attempting to bring her sisters into a new era, allowing men to live on Paradise Island for the first time.  But this divided loyalty and break with tradition is inciting unrest among the Amazons. When a new challenger to the throne arises—one with a familiar face—will Diana be Queen enough to defeat her?  Hot new creative team Meredith Finch (Tales From Oz) and David Finch (BATMAN: THE DARK KNIGHT) take Wonder Woman to War in this action-packed epic!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":4,"review":"","added":9999530,"hdCover":""},{"id":"09894a9","title":"Берсерк. Том 2","author":"Кэнтаро Миура","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004208688/140/de33/Kentaro_Miura__Berserk._Tom_2.jpg","isbn":"978-5-91996-294-6","publisher":"XL Media","pubDate":"2020","language":"Русский","series":"Берсерк","genres":["Комиксы","манга","графические романы"],"annotation":"Во время бесконечных странствий по свету Черный Мечник и навязавшийся к нему в спутники эльф Пак забредают в город, где правит граф-деспот, устроивший охоту на иноверцев и еретиков. И лишь Гатсу известно, что под личиной благочестия скрывается очередной хитрый Апостол, обожающий пытать и убивать ни в чем не повинных людей. Ближе к финалу ожесточенной схватки Гатса с графом бехерит, таинственный предмет, служащий ключом к параллельному измерению, вызывает в тронный зал Десницу Господню, высших существ, издревле управляющих судьбами человечества.  Кто эти пятеро и почему Гатс так неистово рвется отомстить им? Для раскрытия всех тайн нужно вернуться в прошлое к тому моменту, когда молодой и неопытный наемник вступил в Отряд Соколов...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-12","rating":4.5,"review":"","added":9999529,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
