  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09894a8","title":"Берсерк. Том 1","author":"Кэнтаро Миура","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003847606/140/e198/Kentaro_Miura__Berserk._Tom_1.jpg","isbn":"978-5-91996-290-8","publisher":"XL Media","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Одинокий воин, облаченный во все черное и с огромным, в человеческий рост, мечом за спиной, странствует по свету, верша свою месть силам зла. Там, где проходит его путь, неизменно остаются горы трупов, а кровь льется рекой. Народная молва нарекла этого воина Черным мечником, но прежде его звали Гатсом, и он был обычным наемником, пока одно событие не изменило его жизнь навсегда.  В одном из трактиров Гатс случайно спасает жизнь эльфу по имени Пак, и тот, восхищенный мастерством и невероятной силой Черного Мечника, решает отправиться с ним в долгий путь. Он еще не знает, насколько тяжела и полна опасностей жизнь Гатса и как кровожадны и могущественны чудовища, которым тот поклялся отомстить...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-12","rating":4.5,"review":"","added":9999528,"hdCover":""},{"id":"09894a7","title":"Чудо-Женщина. Книга 3. Плоть и кости","author":"Брайан Аззарелло","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002730436/140/fdd3/Brajan_Azzarello__ChudoZhenschina._Kniga_3._Plot_i_kosti.jpg","isbn":"978-5-389-13950-3","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Вопреки собственной воле Диана стала богиней войны и заняла трон Райского острова. Таким поворотом событий недовольна не только сама Диана, но и те, кого она зовёт своей семьей — капризные и гордые боги и богини. Сестра Распря жаждет отомстить за гибель брата. Пророчица Кассандра жаждет попасть на гору Олимп, используя для этого амазонку и ее друзей. А пленный Перворожденный не успокоится, пока не перебьет всех олимпийцев. И начать он намерен с Аполлона…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-12","rating":4,"review":"","added":9999527,"hdCover":""},{"id":"09894a6","title":"Чудо-Женщина. Книга 2. Железо и Война","author":"Брайан Аззарелло","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002511441/140/e5e4/Brajan_Azzarello__ChudoZhenschina._Kniga_2._Zhelezo_i_Vojna.jpg","isbn":"978-5-389-12453-0","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"ПЕРВЫЕ СТАНУТ ПОСЛЕДНИМИ. А ВСЕ ПРОЧИЕ ПАДУТ.  Чудо-Женщина узнала, кто она на самом деле. Дочь царицы амазонок и Зевса, царя богов. И теперь ей предстоит действовать в непростой ситуации, когда все олимпийцы, от ревнивой Геры до блудного Аполлона, стремятся уничтожить и ее, и невинного, но потенциально весьма опасного младенца, которого Зевс недавно зачал со смертной женщиной…  Спасая дитя — и собственную шкуру — Чудо-Женщина собирает разношерстную компанию полубогов и героев. Однако Олимп — не единственный действующий пантеон. На дальнем краю Вселенной раса Новых богов готовится отправить в бой величайшего своего воителя. А в ледяных пустынях на краю Земли восстает древнее божество, снедаемое не менее древними обидами…  Высокооктановая смесь эмоций и действия, благодаря которой перед «Чудо-Женщиной» просто невозможно устоять! На Олимпе и в Космосе «ЧУДО-ЖЕНЩИНА» (коллекционные выпуски # 0, 13–23) с головокружительным блеском демонстрирует современное мифотворчество от звездной команды блестящих сценаристов БРАЙАНА АЗЗАРЕЛЛО («ДЖОКЕР», «100 ПУЛЬ») и КЛИФФА ЧАНГА («ЗЕЛЕНАЯ СТРЕЛА / ЧЕРНАЯ КАНАРЕЙКА»), и талантливых художников ТОНИ ЭЙКИНСА («ДЖОН КОНСТАНТИН, ХЕЛЛБЛЭЙЗЕР») и ГОРАНА СУДЗУКИ («Y: ПОСЛЕДНИЙ МУЖЧИНА»).","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-12","rating":3.5,"review":"","added":9999526,"hdCover":""},{"id":"09894a5","title":"The Boys, Vol. 12: The Bloody Doors Off","author":"Дэрик Робертсон,Гарт Эннис,Russ Braun","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003404282/140/4341/__The_Boys_Vol._12_The_Bloody_Doors_Off.jpg","isbn":"978-1606903735","publisher":"Dynamite Entertainment","pubDate":"2012","language":"","series":"The Boys Book Series","genres":["Комиксы","манга","графические романы"],"annotation":"The war is over and the world is saved. The supes have been beaten down so far they''ll never get up again. So why would anyone want one hundred and eighteen metric tons of the only substance on earth that can kill them all stone dead? Bad days start coming thick and fast, as the Boys are caught in the last throes of the battle they were recruited to fight so long ago. Hughie, all on his own and out of luck, finds himself walking down one last bloody trail — and the truth he finds waiting for him at the end of it will be nothing short of shattering! Billy Butcher''s vengeance comes full circle, in this twelfth and final entry in the story of The Boys.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-12","rating":4.5,"review":"","added":9999525,"hdCover":""},{"id":"09894a4","title":"Сквозь снег","author":"Жак Лоб,Жан-Марк Рошетт,Бенжамин Легран","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004761354/140/bf58/__Skvoz_sneg.jpg","isbn":"978-5-00116-525-5","publisher":"Питер","pubDate":"2020","language":"Русский","series":"Игровая индустрия.Комиксы.Geek-культура","genres":["Комиксы","манга","графические романы","Научная фантастика"],"annotation":"Экологическая катастрофа ввергла мир в новый ледниковый период. Последний оплот человечества — уникальный автономный поезд, который уже много лет колесит вокруг планеты и защищает пассажиров от смертельного холода. Мир этого поезда иерархичен и несправедлив: в голове состава — золотые вагоны для аристократии, которая наслаждается всеми благами нового мира, а в хвосте влачат жалкое существование и умирают от голода и болезней бедняки.  Постапокалиптический мир романа «Сквозь снег» лег в основу сюжета одноименного фильма Пон Чжун Хо, вышедшего в 2013 году. Также по мотивам комикса снят сериал, главную роль в котором сыграла Дженнифер Коннелли. Премьера состоялась в мае 2020 года на Netflix  Настоящее издание включает роман Жака Лоба «Сквозь снег» (1982) и продолжающие повествование о жизни на поезде романы «Странник» (1999) и «Переход» (2000), написанные Бенжамином Леграном. Художник всех трех романов Жан-Марк Рошетт.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-12","rating":4.5,"review":"","added":9999524,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09894a3","title":"Супермен непобежденный","author":"Скотт Снайдер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001492631/140/9885/Skott_Snajder__Supermen_nepobezhdennyj.jpg","isbn":"978-5-389-09800-8","publisher":"Азбука","pubDate":"2016","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"За десятки лет до того, как последний сын Криптона встал на защиту Земли, с неба пришло другое невероятно могущественное существо. И роль, которую оно сыграло в жесточайшей войне за всю историю человечества, стала одной из самых темных тайн Америки. Но все тайное когда-нибудь становится явным. И суперсолдат сорвется с цепи.  Человек из Стали. Лекс Лютор, его злейший враг. Лоис Лейн, его лучший друг. Отец Лоис, генерал Сэм Лейн, неутомимой паранойе которого мог бы позавидовать Бэтмен. Промышленные террористы, от которых тянется загадочный след в прошлое. Все они будут сражаться за право контролировать таинственную машину разрушения. И когда пыль развеется, на поле останется только подлинный Супермен...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-12","rating":3,"review":"","added":9999523,"hdCover":""},{"id":"09894a2","title":"УМРИ!УМРИ!УМРИ!","author":"Роберт Киркман,Скотт М. Гимпл,Крис Бёрнем,Нэйтан Фэйрберн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004535571/140/2309/__UMRIUMRIUMRI.jpg","isbn":"978-5-04-113822-6","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"В этой серии кровищи будет море, пули будут летать туда-сюда и мочилово будет кромешное, потому что написали этот комикс автор «Ходячих мертвецов» Роберт Киркман и шоураннер одноимённого сериала Скотт М. Гимпл, а нарисовал его художник Batman Incorporated Крис Бёрнем!  Нам неприятно это признавать, однако мы живём в мире, полном зла, где злодеи постоянно вершат свои злодеяния. К счастью, в правительстве Соединённых Штатов существует тайное общество, которое работает на благо человечества, используя несистемные методы и индивидуальный террор. Короче, если вы причиняете людям боль, делаете мир ещё хуже, чем он есть, или просто препятствуете добру... то наверняка кто-то прямо сейчас готовится сказать вам...  УМРИ!УМРИ!УМРИ!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-12","rating":3.5,"review":"","added":9999522,"hdCover":""},{"id":"09894a1","title":"Daredevil: Dark Nights #1","author":"Дэвид Лэпэм,Ли Лоуридж,Джимми Палмиотти,Thony Silas,Ли Уикс,показать всех","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001669937/140/27e1/__Daredevil_Dark_Nights_1.jpg","isbn":"0785167994","publisher":"Marvel","pubDate":"2014","language":"Английский","series":"","genres":[],"annotation":"Legendary artist Lee Weeks returns to his favorite hero for \"Angels Unaware!\" A blizzard brings New York to a stand still -- and a young patient lies on death''s door unless Daredevil can get to him in time!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-12","rating":3,"review":"","added":9999521,"hdCover":""},{"id":"09894a0","title":"НАС3","author":"Грант Моррисон,Фрэнк Куайтли","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002006707/140/b381/__NAS3.jpg","isbn":"978-5-389-12160-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2016","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"В недрах сверхсекретного исследовательского центра ВВС США, кибернетическая революция обретает форму. Из обычных домашних животных ученые создали новый класс киборгов, сплав плоти и металла. Этим существам предназначено царить на полях сражений будущего. Венцом проекта является тройка прототипов под кодовым названием НАС3, каждый из которых специально спроектирован и подготовлен к командной работе. Обладающие усиленной нервной системой, вооруженные передовой военной техникой, НАС3 являются идеалом «умного оружия»  – программируемые и при этом автономные, верные и абсолютно безжалостные.  Но как бы ни были они успешны, НАС3 – всего лишь опытные образцы, которые по окончании испытаний будут демонтированы. Однако внутри этих грозных механических оболочек – три растерянных зверя, чья воля к жизни оказывается много сильнее, чем предполагали проектировщики. Столкнувшись с опасностью, НАС3 бегут, вырываясь в пугающий и сложный мир, для которого они в настоящее время представляют серьезную угрозу. Как и те, кто охотится на них. Без устали преследуемые, НАС3 сражаются, объединив огневую мощь батальона со слабым теплым воспоминанием о чем-то под названием «Дом».","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-12","rating":3.5,"review":"","added":9999520,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
