SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098949f","title":"Собакистан","author":"Виталий Терлецкий,Катя","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003403832/140/c4e8/__Sobakistan.jpg","isbn":"978-5-6042551-0-0","publisher":"Терлецки Комикс","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы"],"annotation":"Закрытая социалистическая республика Собакистан открывает границы главам дружественных государств и избранным журналистам в честь репетиции похорон лидера республики – товарища Дружка. Что может пойти не так? Что угодно! Немного стилистики закрытых стран соцлагеря в восьмидесятые годы, немного антропоморфных животных, щепотка шпионских страстей, триллер по вкусу.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-12","rating":4.5,"review":"","added":9999519,"hdCover":""},{"id":"098949e","title":"Несокрушимый Халк. Том 4. Взрыв человечности","author":"Марк Уэйд","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004122084/140/4194/Mark_Uejd__Nesokrushimyj_Halk._Tom_4._Vzryv_chelovechnosti.jpg","isbn":"978-5-91878-423-5","publisher":"Фантастика Книжный Клуб","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Брюс Бэннер хочет спасти мир, но для этого ему придётся одолеть трёх других супергениев планеты! Когда Чёрный Гром, король нелюдей, выпускает мутационный терригенный туман в последней отчаянной попытке защитить своих подданных, все, кто носит в себе соответствующие латентные гены, начинают превращаться в нелюдей. Терригенные коконы появляются по всему Нью-Йорку! Бэннер убеждён, что у него есть лекарство, — жаль, что ему никто не верит. А потому, когда Хэнк Пим, Железный Человек и Зверь выступают против разозлённого учёного, они в полной мере ощущают на себе силу его гнева. Халк сражается с Железным Человеком и Зверем за судьбу мира, а один из лаборантов Бэннера попадает под воздействие терригенного тумана! Имея возможность остановить терригенезис, рассерженный Бэннер пытается спасти своего протеже, но Халк провоцирует появление угрозы ещё большей, нежели туман, и она подставляет Бэннера прямо под прицел убийц! А также: до того как Брюс Бэннер и Тони Старк стали героями, они оба делали оружие — и всё благодаря наставлениям одного человека. ЩИТ отправляет Халка и Железного Человека на поиски величайшего оружейника, но не превратятся ли они сами по возвращении в оружие массового поражения?  Издание содержит выпуски «Несокрушимый Халк» № 16–20 и «Летопись» № 1, написанные Марком Уэйдом и Джеффом Паркером и проиллюстрированные Махмудом Асраром и Джо Беннеттом совместно с Клеем Мэнном, Джереми Раапаком и Томом Грамметтом.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-12","rating":3,"review":"","added":9999518,"hdCover":""},{"id":"098949d","title":"Сорвиголова. Том 7","author":"Марк Уэйд","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002103131/140/40e3/Mark_Uejd__Sorvigolova._Tom_7.jpg","isbn":"978-5-91339-486-6","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Репутация Человека без Страха поставлена под угрозу, когда он встречает Легион Монстров. Но оборотни, зомби и чудовище Франкенштейна — едва ли главные ужасы в жизни Сорвиголовы. Его лучший друг болен раком, и никто из коллег-супергероев не способен ему помочь. Скрытые от посторонних глаз силы сеют вокруг невежество и злобу, а костюмированные маньяки наподобие Шута готовы продать душу за материальные блага.  Сторонники белой расы, известные как «Сыновья Змея», проникли во все уровни уголовно-правовой системы. Они зажгли искру ненависти в городе, а Шут уже держит над готовым разгореться пламенем спичку. Может, Сорвиголова и собрался уехать из Нью-Йорка в поисках новой жизни, но гореть городу он не позволит. Мир Мэтта Мёрдока переворачивается с ног на голову, в то время как первая фаза признанной критиками работы Марка Уэйда достигает своей кульминации.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-12","rating":2.5,"review":"","added":9999517,"hdCover":""},{"id":"098949c","title":"Сорвиголова. Том 6","author":"Tom Peyer,Крис Сэмни,Марк Уэйд,Маттео Скалера,Хавьер Родригес,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002038298/140/236b/__Sorvigolova._Tom_6.jpg","isbn":"978-5-91339-447-7","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Жизнь адвоката и супергероя Сорвиголовы оказывается под угрозой, когда против него выступает сама судебная система! Пока Мэтт в отсутствие своего партнёра Фогги Нельсона, проходящего курс лечения от рака, пытается удержать на плаву собственную юридическую фирму, новое дело открывает забытую главу из его прошлого. Сорвиголова оказывается в центре заговора, охватившего высшие эшелоны нью-йоркской системы правосудия. Кроме того, герою придётся справиться с международной и межгалактической угрозами, объединившись с Халком и Серебряным Сёрфером соответственно!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-12","rating":3,"review":"","added":9999516,"hdCover":""},{"id":"098949b","title":"Сорвиголова. Том 5","author":"Марк Уэйд","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001634402/140/e6dd/Mark_Uejd__Sorvigolova._Tom_5.jpg","isbn":"978-5-91339-411-8","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"Сорвиголова","genres":["Комиксы","манга","графические романы"],"annotation":"Мэтт Мёрдок узнаёт ужасные новости о том, кто ему близок.  Перестанет ли он быть супергероем, чтобы спасти одного из самых дорогих друзей? Пока в жизни Мэтта разыгрывается драма с медицинским уклоном, из тени выходит таинственный враг, стоявший за всеми недавними неприятностями Сорвиголовы. И он готов разыграть свой козырь!  Человеку Без Страха противостоит практически его копия - несокрушимый противник, загадочным образом связанный с тем инцидентом, после которого юный Мэтт получил свои способности. Кульминация первых двух лет работы Марка Уэйда над обласканной критиками серией комиксов - в этом умопомрачительном приключении!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-12","rating":3,"review":"","added":9999515,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098949a","title":"Сорвиголова. Том 4","author":"Марк Уэйд","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001601797/140/5524/Mark_Uejd__Sorvigolova._Tom_4.jpg","isbn":"978-5-91339-392-0","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"Сорвиголова","genres":["Комиксы","манга","графические романы"],"annotation":"Сорвиголове предстоит срочная операция на мозге: его друг-мститель Хэнк Пим пробирается в голову героя, чтобы уничтожить микророботов Доктора Дума, лишивших Рогатого всех чувств. Когда боты наносят ответный удар, друзья начинают лучше понимать невзгоды друг друга, ведь Человеку-Муравью приходится сражаться вслепую! Но процесс реабилитации Сорвиголовы идёт насмарку, когда тот начинает сомневаться в реальности происходящего. Его лучший друг Фогги Нельсон, веря, что Мэтт сходит с ума и представляет опасность для себя и окружающих, разрывает все их.отношения - как партнёрские, так и дружеские. Призраки прошлого преследуют Сорвиголову в крышесносящем приключении, и герою предстоит усомниться в собственном рассудке, встретившись лицом к лицу с новым опасным злодеем по прозвищу Койот!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-12","rating":3.5,"review":"","added":9999514,"hdCover":""},{"id":"0989499","title":"Сорвиголова. Том 3","author":"Марк Уэйд","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001533632/140/b4c8/Mark_Uejd__Sorvigolova._Tom_3.jpg","isbn":"978-5-91339-375-3","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Сорвиголова и его давний друг и напарник Человек-паук объединяются не с одним, а сразу с двумя Карателями после того, как Фрэнк Касл вместе с киллершей-стажёром Рэйчел Коул-Алвес чуть не убивают Человека Без Страха в попытке завладеть Омегадиском.  Отчаянно пытаясь положить конец охоте на себя со стороны мировой преступности, Сорвиголова убеждает героев развязать войну между противоборствующими группировками, уничтожив диск на глазах у бандитов, а секретные данные отдать на хранение Мстителям. Но план катится к чертям, а жизнь Сорвиголовы виснет на волоске, когда один из героев предаёт остальных, чтобы лично поставить международную преступную сеть на колени!  Кроме того, Мэтт Мёрдок отлично проводит время на свидании с помощницей прокурора Кирстен МакДаффи, пока у них на пути, уничтожая всех вокруг, не появляется «Чёрный спектр»!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":2,"review":"","added":9999513,"hdCover":""},{"id":"0989498","title":"Сорвиголова. Том 2","author":"Марк Уэйд","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001463683/140/ac64/Mark_Uejd__Sorvigolova._Tom_2.jpg","isbn":"978-5-91339-323-Х","publisher":"Комильфо","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Из лабораторий \"Горизонт\" пропадает высокотехнологичное устройство, и теперь в компании Человека-паука Сорвиголова должен найти пропажу и снять с Чёрной Кошки обвинения в воровстве. Ценой невероятных усилий Стенолаз и Человек без Страха осознают, что в деле с ограблением не так уже всё очевидно, да и Кошку сложно назвать невинной жертвой! Вдобавок ко всему кто-то ворует тела из могил на одном из нью-йоркских кладбищ, гроб с Джеком \"Бойцом\" Мёрдоком тоже пропал! Сорвиголова устремляется под землю, чтобы сразиться с мерзким злодеем, стоящим за осквернением памяти усопших.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":2.5,"review":"","added":9999512,"hdCover":""},{"id":"0989497","title":"Сорвиголова. Том 1","author":"Марк Уэйд,Паоло Ривера,Маркос Мартин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001284166/140/d81d/__Sorvigolova._Tom_1.jpg","isbn":"978-5-91339-323-4","publisher":"Комильфо","pubDate":"2015","language":"Русский","series":"Сорвиголова","genres":["Комиксы","манга","графические романы"],"annotation":"Мэтт Мёрдок снова в Нью-Йорке, но не все ему рады. Он возвращается к адвокатской практике и берётся за дело о превышении полномочий - но кто-то пытается запугать его подзащитного. Пока Мэтт ведёт судебный процесс, Сорвиголова сражается с Кло, повелителем звука! Затем слепой в прямом смысле ведёт слепого, помогая слабовидящему клиенту избежать угрозы смерти, которой он подвергся из-за того, что становится случайным обладателем ключа к всемирному заговору известных злодеев. Сможет ли Сорвиголова защитить юношу и переиграть международную преступную организацию, или безжалостный убийца доберётся до них раньше? В книге собраны комиксы \"Сорвиголова\" № 1-6 - от автора легендарного \"Капитана Америка\" и \"Фантастической Четвёрки\" Марка Уэйда и звёздных художников \"Человека-паука\" Паоло Риверы и Маркоса Мартина.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":2.5,"review":"","added":9999511,"hdCover":""},{"id":"0989496","title":"Daredevil: End of Days","author":"Брайан Майкл Бендис,Дэвид Мак","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003015465/140/aada/__Daredevil_End_of_Days.jpg","isbn":"9780785124207","publisher":"Marvel","pubDate":"2013","language":"Английский","series":"","genres":[],"annotation":"Revealed at last...how it all ends for the Man Without Fear! In the near future, the Kingpin and Daredevil have been murdered - but that''s just the beginning of the story. Investigative reporter Ben Urich has one last story to write...what was Matt Murdock''s final secret? Ben digs deep into the seedy underbelly of the Marvel Universe, tracking down Matt''s buried sins and past loves to discover the secrets behind his death - but who is the new Daredevil that''s tracking Ben? You won''t believe your eyes when the mystery behind Daredevil''s final days stands revealed! It''s a story years in the making, brought to you by some of the greatest creators in Daredevil history!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":4.5,"review":"","added":9999510,"hdCover":""},{"id":"0989495","title":"Black Panther: The Most Dangerous Man Alive: The Kingpin of Wakanda","author":"Дэвид Лисс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003224532/140/f9ff/Devid_Liss__Black_Panther_The_Most_Dangerous_Man_Alive_The_Kingpin_of_Wakanda.jpg","isbn":"9780785160373","publisher":"Marvel","pubDate":"2012","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Who is murdering the citizens of Hell''s Kitchen that The Panther has previously rescued? That''s what T''Challa wants to know-and he only has hours to solve the mystery before the killer strikes again! Find out why IGN says David liss'' revamped Black Panther series continues to be just what the hero needs.  Collecting: Black Panther: The Most Dangerous Man Alive 523.1, 525-529","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":1.5,"review":"","added":9999509,"hdCover":""},{"id":"0989494","title":"The walking dead: The alien.","author":"Брайан К. Вон,Маркос Мартин","type":"Книга","cover":"https://i.livelib.ru/workpic/1001566717/140/ff85/__The_walking_dead_The_alien..jpg","isbn":"","publisher":"","pubDate":"","language":"Английский","series":"","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":3.5,"review":"","added":9999508,"hdCover":""}]');
